            ExerciseItem(prompt: "What does it mean when a call goes straight to voicemail?", options: ["The person has blocked you", "The person's phone may be off, out of range, or set to Do Not Disturb", "The call was dropped", "Your phone has a bad connection"], correctAnswer: "The person's phone may be off, out of range, or set to Do Not Disturb", explanation: "Calls going directly to voicemail often mean the person's phone is off, has no signal, or calls are being silenced."),
            ExerciseItem(prompt: "If you are in a car accident and need help, what should you do first?", options: ["Call your insurance company", "Call 911 to report the accident and request help", "Drive to the nearest hospital", "Take photos of the damage"], correctAnswer: "Call 911 to report the accident and request help", explanation: "Calling 911 ensures that police and emergency medical services are dispatched to assist."),
            ExerciseItem(prompt: "What does it mean if your smoke detector is beeping once every 30 to 60 seconds?", options: ["There is a fire nearby", "The battery is low and needs to be replaced", "The detector has been triggered by steam", "The detector is working correctly"], correctAnswer: "The battery is low and needs to be replaced", explanation: "A single chirp every 30 to 60 seconds is the standard low-battery warning signal for smoke detectors."),
            ExerciseItem(prompt: "What is the Poison Control hotline number in the US?", options: ["911", "811", "1-800-222-1222", "311"], correctAnswer: "1-800-222-1222", explanation: "The US Poison Control Center can be reached at 1-800-222-1222, available 24 hours a day."),
            ExerciseItem(prompt: "If you feel chest pain and shortness of breath, what should you do?", options: ["Wait and see if it gets better", "Call 911 or have someone drive you to the emergency room immediately", "Take an extra dose of your blood pressure medication", "Drink water and rest"], correctAnswer: "Call 911 or have someone drive you to the emergency room immediately", explanation: "Chest pain and shortness of breath can be signs of a heart attack or other serious emergency requiring immediate care."),
