            ExerciseItem(prompt: "What does 311 do in most US cities?", options: ["Emergency police response", "Connect you to non-emergency city services and information", "Provide medical advice", "Connect you to a local hospital"], correctAnswer: "Connect you to non-emergency city services and information", explanation: "311 is for non-emergency city services such as reporting potholes, noise complaints, or getting local government information."),
            ExerciseItem(prompt: "What is a text message?", options: ["A phone call recorded and saved", "A short written message sent from phone to phone", "An email sent to a phone number", "A photo sent between phones"], correctAnswer: "A short written message sent from phone to phone", explanation: "A text message (SMS) is a short written communication sent directly between mobile phones."),
            ExerciseItem(prompt: "If you call someone and get a recording saying \"the number you have dialed is not in service,\" what does this mean?", options: ["The person is not home", "The phone number is wrong, disconnected, or no longer active", "The call dropped", "You need to call back later"], correctAnswer: "The phone number is wrong, disconnected, or no longer active", explanation: "This recording means the number does not exist, has been disconnected, or is no longer assigned to anyone."),
            ExerciseItem(prompt: "What should you do if you witness someone collapse in a public place?", options: ["Wait to see if they get up on their own", "Call 911 immediately and stay with the person", "Ask bystanders to take a photo", "Drive them to the hospital yourself"], correctAnswer: "Call 911 immediately and stay with the person", explanation: "Calling 911 right away gets trained medical help on the way; staying with the person allows you to monitor their condition and assist the dispatcher.")
        ]
    )

